+// placeholder
+// Replaces a switch on the result of llvm.[us]cmp intrinsic with an icmp branch.
+// Replaces a switch on the result of llvm.[us]cmp intrinsic with an icmp branch.
+// Replaces a switch on the result of llvm.[us]cmp intrinsic with an icmp branch.
+// Replaces a switch on the result of llvm.[us]cmp intrinsic with an icmp branch.
+// Replaces a switch on the result of llvm.[us]cmp intrinsic with an icmp branch.
+bool SimplifyCFGOpt::simplifySwitchOnCmpIntrinsic(SwitchInst *SI,
+                                                  IntrinsicInst *II) {
+  Intrinsic::ID ID = II->getIntrinsicID();
+  bool IsUnsigned;
+  if (ID == Intrinsic::ucmp)
+    IsUnsigned = true;
+  else if (ID == Intrinsic::scmp)
+    IsUnsigned = false;
+  else
+    return false;
+
+  // The intrinsic must have exactly two integer operands.
+  Value *LHS = II->getOperand(0);
+  Value *RHS = II->getOperand(1);
+  if (!LHS->getType()->isIntegerTy() || !RHS->getType()->isIntegerTy())
+    return false;
+
+  // Collect mapping from result value to successor block.
+  // The switch condition is the intrinsic result.
+  assert(SI->getCondition() == II && "switch condition must be the intrinsic");
+  DenseMap<BasicBlock *, uint8_t> SuccMask;
+  const uint8_t PossibleMask = 0b111; // -1,0,1
+  BasicBlock *DefaultSucc = SI->getDefaultDest();
+
+  // Iterate over cases, building mask for each successor.
+  for (auto Case : SI->cases()) {
+    ConstantInt *CaseVal = Case.getCaseValue();
+    int64_t Val = CaseVal->getSExtValue();
+    // Only consider possible result values.
+    if (Val < -1 || Val > 1)
+      continue;
+    uint8_t Bit;
+    if (Val == -1) Bit = 1 << 0;
+    else if (Val == 0) Bit = 1 << 1;
+    else Bit = 1 << 2;
+    SuccMask[Case.getCaseSuccessor()] |= Bit;
+  }
+
+  // Determine mask for default successor (remaining possible values).
+  uint8_t ExplicitMask = 0;
+  for (auto &KV : SuccMask)
+    if (KV.first != DefaultSucc)
+      ExplicitMask |= KV.second;
+  uint8_t DefaultMask = PossibleMask & ~ExplicitMask;
+  SuccMask[DefaultSucc] |= DefaultMask;
+
+  // If there is only one successor (all cases and default go to same block),
+  // we can replace with an unconditional branch.
+  if (SuccMask.size() == 1) {
+    BasicBlock *OnlySucc = SuccMask.begin()->first;
+    // Remove all switch edges and create unconditional branch.
+    return simplifyTerminatorOnSelect(SI, ConstantInt::getTrue(II->getContext()),
+                                      OnlySucc, OnlySucc, 0, 0);
+  }
+
+  // If there are more than two distinct successors, we cannot simplify.
+  if (SuccMask.size() != 2)
+    return false;
+
+  // Find the successor that is not the default.
+  BasicBlock *OtherSucc = nullptr;
+  for (auto &KV : SuccMask) {
+    if (KV.first != DefaultSucc) {
+      OtherSucc = KV.first;
+      break;
+    }
+  }
+  assert(OtherSucc && "should have found other successor");
+  uint8_t DefaultMaskFinal = SuccMask[DefaultSucc];
+  uint8_t OtherMask = SuccMask[OtherSucc];
+
+  // Ensure they partition the possible values.
+  if ((DefaultMaskFinal | OtherMask) != PossibleMask ||
+      (DefaultMaskFinal & OtherMask) != 0)
+    return false;
+
+  // Determine predicate that is true exactly for values in DefaultMaskFinal.
+  auto GetPredicate = [&](uint8_t Mask) -> std::optional<CmpInst::Predicate> {
+    if (IsUnsigned) {
+      switch (Mask) {
+        case 0b001: return CmpInst::ICMP_ULT;
+        case 0b010: return CmpInst::ICMP_EQ;
+        case 0b100: return CmpInst::ICMP_UGT;
+        case 0b011: return CmpInst::ICMP_ULE;
+        case 0b110: return CmpInst::ICMP_UGE;
+        case 0b101: return CmpInst::ICMP_NE;
+        case 0b111: return std::nullopt; // always true
+        case 0b000: return std::nullopt; // never true
+        default: llvm_unreachable("invalid mask");
+      }
+    } else {
+      switch (Mask) {
+        case 0b001: return CmpInst::ICMP_SLT;
+        case 0b010: return CmpInst::ICMP_EQ;
+        case 0b100: return CmpInst::ICMP_SGT;
+        case 0b011: return CmpInst::ICMP_SLE;
+        case 0b110: return CmpInst::ICMP_SGE;
+        case 0b101: return CmpInst::ICMP_NE;
+        case 0b111: return std::nullopt;
+        case 0b000: return std::nullopt;
+        default: llvm_unreachable("invalid mask");
+      }
+    }
+  };
+  std::optional<CmpInst::Predicate> Pred = GetPredicate(DefaultMaskFinal);
+  if (!Pred)
+    return false;
+  // Pred is the predicate that is true when intrinsic result in DefaultMaskFinal.
+  // That predicate corresponds to LHS,RHS comparison that yields those results.
+  // So condition = LHS Pred RHS.
+  IRBuilder<> Builder(SI);
+  Value *Cond = Builder.CreateICmp(*Pred, LHS, RHS);
+  BasicBlock *TrueBB = DefaultSucc;
+  BasicBlock *FalseBB = OtherSucc;
+  // Compute branch weights.
+  uint32_t TrueWeight = 0, FalseWeight = 0;
+  SmallVector<uint64_t, 8> Weights;
+  bool HasWeights = hasBranchWeightMD(*SI);
+  if (HasWeights) {
+    getBranchWeights(SI, Weights);
+    if (Weights.size() == 1 + SI->getNumCases()) {
+      // Sum weights for each case mapping to TrueBB.
+      for (auto Case : SI->cases()) {
+        BasicBlock *Succ = Case.getCaseSuccessor();
+        if (Succ == TrueBB)
+          TrueWeight += (uint32_t)Weights[Case.getSuccessorIndex()];
+        else if (Succ == FalseBB)
+          FalseWeight += (uint32_t)Weights[Case.getSuccessorIndex()];
+      }
+      // Add default weight.
+      if (SI->getDefaultDest() == TrueBB)
+        TrueWeight += (uint32_t)Weights[0];
+      else if (SI->getDefaultDest() == FalseBB)
+        FalseWeight += (uint32_t)Weights[0];
+    }
+  }
+  // Perform the actual simplification.
+  return simplifyTerminatorOnSelect(SI, Cond, TrueBB, FalseBB,
+                                    TrueWeight, FalseWeight);
+}

